INSERT INTO video_files ( file_name, creation_date, modification_date, last_access_time, file_format, file_size,file_size_format, file_score, file_md5, file_path, actor, video_code ) VALUES
( #{item.fileName}, #{item.creationDate}, #{item.modificationDate}, #{item.lastAccessTime}, #{item.fileFormat}, #{item.fileSize}, #{item.fileSizeFormat}, #{item.fileScore}, #{item.fileMd5}, #{item.filePath}, #{item.actor}, #{item.videoCode} )
ON DUPLICATE KEY UPDATE file_name = VALUES(file_name), creation_date = VALUES(creation_date), modification_date = VALUES(modification_date), last_access_time = VALUES(last_access_time), file_format = VALUES(file_format), file_size = VALUES(file_size), file_size_format = VALUES(file_size_format), file_score = VALUES(file_score), file_md5 = VALUES(file_md5), actor = VALUES(actor), video_code = VALUES(video_code);
